
.martial-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.m-section h3 {
  font-size: 13px;
  font-weight: 600;
  color: var(--c-bronze);
  margin: 0 0 8px;
  display: flex;
  align-items: center;
  gap: 5px;
}

.m-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.m-item {
  padding: 8px 10px;
  background: rgba(139, 105, 20, 0.04);
  border: 1px solid rgba(139, 105, 20, 0.12);
  border-radius: 3px;
}

.m-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 4px;
}

.m-name {
  font-weight: 600;
  font-size: 12px;
}

.m-tier {
  font-size: 11px;
  color: var(--c-stone);
}

.m-desc {
  font-size: 11px;
  color: var(--c-stone);
  line-height: 1.4;
  margin-bottom: 6px;
}

.m-bar {
  height: 5px;
  background: rgba(44, 36, 27, 0.06);
  border-radius: 3px;
  overflow: hidden;
}

.m-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.5s ease;
}

.m-fill.inner {
  background: linear-gradient(90deg, #7c4a8c, #a66dba);
}

.m-fill.outer {
  background: linear-gradient(90deg, var(--c-cinnabar), #e06050);
}

.m-fill.dodge {
  background: linear-gradient(90deg, var(--c-jade), #6ab77a);
}

.empty {
  font-size: 11px;
  color: var(--c-stone);
  font-style: italic;
  padding: 6px 0;
}

.power-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding-top: 8px;
  border-top: 1px solid rgba(139, 105, 20, 0.15);
  font-size: 12px;
}

.power-label {
  color: var(--c-stone);
}

.power-value {
  font-weight: 700;
  color: var(--c-cinnabar);
  font-size: 14px;
}
