
.world-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.w-section h3 {
  font-size: 13px;
  font-weight: 600;
  color: var(--c-bronze);
  margin: 0 0 8px;
  display: flex;
  align-items: center;
  gap: 5px;
}

.area-info {
  font-size: 11px;
  color: var(--c-stone);
  line-height: 1.5;
  padding: 8px;
  background: rgba(139, 105, 20, 0.04);
  border-radius: 3px;
  margin-bottom: 8px;
}

.explored {
  display: flex;
  gap: 6px;
  align-items: flex-start;
}

.exp-label {
  font-size: 11px;
  color: var(--c-stone);
  flex-shrink: 0;
  margin-top: 2px;
}

.exp-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
}

.exp-tag {
  font-size: 10px;
  padding: 2px 6px;
  background: rgba(139, 105, 20, 0.08);
  color: var(--c-stone);
  border-radius: 2px;
  border: 1px solid rgba(139, 105, 20, 0.12);
}

.npc-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.npc-item {
  padding: 8px 10px;
  background: rgba(139, 105, 20, 0.03);
  border: 1px solid rgba(139, 105, 20, 0.1);
  border-radius: 3px;
}

.npc-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 2px;
}

.npc-name {
  font-weight: 600;
  font-size: 12px;
}

.npc-loc {
  font-size: 10px;
  color: var(--c-stone);
}

.npc-iden {
  font-size: 11px;
  color: var(--c-stone);
  margin-bottom: 4px;
}

.npc-meta {
  display: flex;
  gap: 6px;
}

.npc-relation {
  font-size: 10px;
  padding: 1px 5px;
  border-radius: 2px;
  background: rgba(44, 36, 27, 0.06);
}

.npc-relation.loved {
  background: rgba(194, 58, 48, 0.1);
  color: var(--c-cinnabar);
}

.npc-relation.friendly {
  background: rgba(74, 124, 89, 0.1);
  color: var(--c-jade);
}

.npc-relation.hostile {
  background: rgba(139, 105, 20, 0.1);
  color: var(--c-bronze);
}

.npc-relation.hated {
  background: rgba(44, 36, 27, 0.1);
  color: var(--c-ink);
}

.npc-aff {
  font-size: 10px;
  color: var(--c-stone);
}

.affairs {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.affair {
  display: flex;
  gap: 8px;
  align-items: flex-start;
}

.aff-dot {
  width: 6px;
  height: 6px;
  background: var(--c-cinnabar);
  border-radius: 50%;
  margin-top: 5px;
  flex-shrink: 0;
}

.aff-name {
  font-weight: 600;
  font-size: 12px;
}

.aff-desc {
  font-size: 11px;
  color: var(--c-stone);
  line-height: 1.4;
}

.empty {
  font-size: 11px;
  color: var(--c-stone);
  font-style: italic;
  text-align: center;
  padding: 12px 0;
}
