
.wuxia-card {
  width: 100%;
  max-width: 720px;
  background: linear-gradient(180deg, var(--c-parchment) 0%, #ebe4d6 100%);
  border: 2px solid var(--c-bronze);
  border-radius: 4px;
  box-shadow: 0 0 0 1px rgba(139, 105, 20, 0.3), 0 4px 12px rgba(44, 36, 27, 0.15);
  display: flex;
  flex-direction: column;
  font-family: var(--font-wuxia);
  color: var(--c-ink);
  font-size: 13px;
  line-height: 1.5;
  margin: 0 auto;
  overflow: hidden;
}

.card-header {
  background: linear-gradient(90deg, var(--c-ink) 0%, #3d3025 100%);
  color: var(--c-parchment);
  padding: 10px 14px;
}

.title-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 6px;
}

.game-title {
  font-size: 18px;
  font-weight: 700;
  margin: 0;
  letter-spacing: 2px;
  color: var(--c-gold);
}

.realm-badge {
  font-size: 11px;
  padding: 2px 8px;
  border: 1px solid var(--c-cinnabar);
  color: var(--c-cinnabar);
  border-radius: 2px;
}

.world-info {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  font-size: 11px;
  opacity: 0.85;
}

.info-item {
  display: inline-flex;
  align-items: center;
  gap: 4px;
}

.content-area {
  padding: 10px 14px 14px;
  min-height: 0;
}

.tab-pane {
  animation: fadeIn 0.35s ease;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(4px); }
  to { opacity: 1; transform: translateY(0); }
}
