
.inv-panel {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.equip-row {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 6px;
}

.equip-cell {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 6px;
  background: rgba(139, 105, 20, 0.04);
  border: 1px solid rgba(139, 105, 20, 0.12);
  border-radius: 3px;
}

.equip-label {
  font-size: 10px;
  color: var(--c-stone);
  margin-bottom: 2px;
}

.equip-val {
  font-size: 11px;
  font-weight: 600;
  text-align: center;
}

.inv-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--c-bronze);
  margin: 0;
  display: flex;
  align-items: center;
  gap: 5px;
}

.inv-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.inv-item {
  padding: 7px 10px;
  background: rgba(139, 105, 20, 0.03);
  border-left: 2px solid var(--c-bronze);
  border-radius: 0 3px 3px 0;
}

.inv-name {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-weight: 600;
  font-size: 12px;
  margin-bottom: 2px;
}

.inv-qty {
  font-size: 11px;
  color: var(--c-stone);
  font-weight: 400;
}

.inv-desc {
  font-size: 11px;
  color: var(--c-stone);
  line-height: 1.4;
}

.empty {
  font-size: 11px;
  color: var(--c-stone);
  font-style: italic;
  text-align: center;
  padding: 12px 0;
}
