
.status-bars {
  padding: 10px 14px;
  background: rgba(139, 105, 20, 0.04);
  border-bottom: 1px dashed var(--c-bronze);
}

.bar-row {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
}

.bar-row:last-child {
  margin-bottom: 0;
}

.bar-label {
  width: 52px;
  font-size: 12px;
  font-weight: 600;
  color: var(--c-stone);
  flex-shrink: 0;
}

.bar-track {
  flex: 1;
  height: 10px;
  background: rgba(44, 36, 27, 0.08);
  border-radius: 5px;
  overflow: hidden;
  position: relative;
}

.bar-fill {
  height: 100%;
  border-radius: 5px;
  transition: width 0.6s ease;
}

.bar-fill.hp {
  background: linear-gradient(90deg, var(--c-cinnabar), #e06050);
}

.bar-fill.mp {
  background: linear-gradient(90deg, #4a7c9c, #6ba3c7);
}

.bar-fill.food {
  background: linear-gradient(90deg, var(--c-jade), #6ab77a);
}

.bar-value {
  width: 70px;
  text-align: right;
  font-size: 11px;
  color: var(--c-stone);
  font-variant-numeric: tabular-nums;
  flex-shrink: 0;
}

.bar-value.danger {
  color: var(--c-blood);
  font-weight: 700;
}

.status-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-top: 8px;
}

.meta-tag {
  font-size: 11px;
  padding: 2px 7px;
  border-radius: 2px;
  background: rgba(139, 105, 20, 0.08);
  color: var(--c-stone);
  border: 1px solid rgba(139, 105, 20, 0.15);
}

.meta-tag.poison {
  background: rgba(194, 58, 48, 0.1);
  color: var(--c-cinnabar);
  border-color: rgba(194, 58, 48, 0.25);
}

.meta-tag.money {
  background: rgba(184, 151, 61, 0.1);
  color: var(--c-bronze);
  border-color: rgba(184, 151, 61, 0.25);
}

.meta-tag.fame.evil {
  background: rgba(44, 36, 27, 0.08);
  color: var(--c-ink);
}
